var e=[{id:`L6_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`어…….`,JPN:`ど……`,ENG:`Uh...`,TWN:`怎……`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`어째서……?`,JPN:`どうして……`,ENG:`But why...?`,TWN:`怎麼會……？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`어째서 당신이 여기에……?`,JPN:`どうしてあなたがここに……？`,ENG:`W-why are you here...?`,TWN:`為什麼你會……？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_FAKE`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`아가씨?`,JPN:`お嬢様？`,ENG:`Miss Jia?`,TWN:`小姐？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`안 됩니다, 아가씨! 총을 거두세요! 아가씨의 숙부님이십니다!`,JPN:`いけません、お嬢様！　銃を下ろしてください！　お嬢様の叔父様なのですよ！`,ENG:`No, Jia! You can’t! He’s your uncle!`,TWN:`不可以，小姐！把槍放下！再怎麼說他也是你的叔叔！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`EXECUTIVE_NPC_ALPHA_MAJOR`,text:{KOREA:`큭큭...... 내가 선수를 빼앗겼군, 이 실장......`,JPN:`ククッ……私が先手を取られたようだな、シノザキ室長……`,ENG:`Keke... Looks like I was too slow, Chief Lee...`,TWN:`唔……竟然被你先下手為強，李室長……`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`EXECUTIVE_NPC_ALPHA_MAJOR`,text:{KOREA:`저 빌어먹을 괴물은…….`,JPN:`あのクソ化け物は……`,ENG:`That monster is...`,TWN:`該死的怪物……`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`DRIVER_NPC_ALPHA_NULL`,text:{KOREA:`으아아아악!`,JPN:`うわあああっ！`,ENG:`Aaaagh!!`,TWN:`啊啊啊啊！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`DRIVER_NPC_ALPHA_NULL`,text:{KOREA:`부, 부회장님이! 부회장님이 죽었어!`,JPN:`ふ、副会長が！　副会長が死んでしまった！`,ENG:`Y-you...! You killed the Vice Chairman!`,TWN:`副…副會長！副會長死了！`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`아가씨……. 대체 왜……?`,JPN:`お嬢様……いったいどうして……？`,ENG:`Jia... W-why...?`,TWN:`小姐……你為什麼……？`},stage:{bg:`DONGDAEMUN_DARK`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`아하, 이진 언니는 이노베이션에 오기 전에는 숙부님의 비서셨죠?`,JPN:`残念ですね。そういえば、ホノカさんはイノベーションに来る前、叔父様の秘書をされていましたよね？`,ENG:`That’s right! You were Uncle’s secretary before joining Innovation.`,TWN:`哦～李珍姐之前是叔叔的秘書對吧？`},stage:{bg:`GAUNTLET`,slots:{L:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:`……네.`,JPN:`……はい。`,ENG:`Yes...`,TWN:`……是的，`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`LEEJIN_ALPHA_NULL_NULL`,text:{KOREA:` 이젠 아니지만요.`,JPN:`今はもう違いますが……`,ENG:`But not anymore.`,TWN:`但現在不是。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`LEEJIN_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그렇구나. 오랫동안 못 보셨으니까 비서 시절 생각이 많이 나시겠네요.`,JPN:`そうでしたね。叔父様とは久しぶりに会いますし、
色々と秘書時代のことを思い出すひと時になりそうですね。`,ENG:`I see. Then I’m sure you were delighted to see him again.`,TWN:`那你們這麼久不見，應該會想起很多以前的事吧～`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};